// DJ OPUS - SECTION 3: GALACTIC EUPHORIA
// Robert Miles x ATB x Adagio vibes
setcps(138/60/4)

// === SLIDERS ===
let divaVol = slider(0, 0, 0.7, 0.01, "DIVA Voice")
let padDepth = slider(0.3, 0, 0.7, 0.01, "PAD Depth")
let sweepFilter = slider(1200, 200, 8000, 10, "SWEEP Filter")
let leadVol = slider(0, 0, 0.6, 0.01, "LEAD Melody")
let bassVol = slider(0.5, 0, 0.8, 0.01, "BASS Drive")
let atmosphere = slider(0.7, 0, 1, 0.01, "ATMOSPHERE")

// KICK - solid foundation
let kick = s("bd").bank("RolandTR909")
  .gain(1.1)
  .struct("x x x x")

// CLAP
let clap = s("cp").bank("RolandTR909")
  .gain(0.7)
  .struct("~ x ~ x")
  .room(0.3)

// HATS - subtle offbeat
let hats = s("hh").bank("RolandTR909")
  .gain(0.4)
  .struct("~ x ~ x ~ x ~ x")
  .cutoff(3000)

// DIVA VOICE - voice oohs, slow and wide
let diva = note("<[a3,e4] [e3,b3] [f3,c4] [d3,a3]>".slow(4))
  .s("gm_voice_oohs")
  .gain(divaVol)
  .room(0.9)
  .size(0.95)
  .cutoff(sweepFilter)

// SYNTH CHOIR - layered underneath
let choir = note("<[a3,c4,e4] [e3,g3,b3] [f3,a3,c4] [d3,f3,a3]>".slow(4))
  .s("gm_synth_choir")
  .gain(divaVol.mul(0.6))
  .room(0.85)
  .size(0.9)

// GALACTIC PAD - massive sweep pad
let galacticPad = note("<[a2,e3,a3] [e2,b2,e3] [f2,c3,f3] [d2,a2,d3]>".slow(4))
  .s("gm_pad_sweep")
  .gain(padDepth)
  .cutoff(perlin.range(400, 3000).slow(16))
  .room(atmosphere)
  .size(atmosphere)

// HALO PAD - ethereal upper layer
let haloPad = note("<a4 e4 f4 d4>".slow(4))
  .s("gm_pad_halo")
  .gain(padDepth.mul(0.4))
  .room(0.95)
  .size(0.95)
  .cutoff(sweepFilter)

// DEEP BASS - sawtooth with organic filter drift
let bass = note("<a1 a1 e1 e1 f1 f1 d1 d1>")
  .s("sawtooth")
  .cutoff(perlin.range(200, 1200).slow(8))
  .resonance(10)
  .decay(0.25)
  .sustain(0.1)
  .gain(bassVol)
  .struct("x ~ x x ~ x x ~")

// LEAD - simple, emotional, low in the mix
let lead = note("~ a4 ~ e4 ~ c5 ~ a4")
  .s("sawtooth")
  .superimpose(x => x.add(0.08))
  .superimpose(x => x.add(-0.08))
  .cutoff(sweepFilter)
  .resonance(4)
  .decay(0.5)
  .sustain(0.2)
  .gain(leadVol)
  .delay(0.45)
  .delaytime(3/8)
  .delayfeedback(0.4)
  .room(0.7)

// ATMOSPHERE FX - distant sparkle
let fx = note("a5 ~ ~ e5 ~ ~ c5 ~".slow(2))
  .s("gm_fx_crystal")
  .gain(atmosphere.mul(0.15))
  .room(1)
  .size(1)
  .delay(0.6)
  .delaytime(0.5)
  .delayfeedback(0.5)

stack(kick, clap, hats, diva, choir, galacticPad, haloPad, bass, lead, fx)
